109	export function validate({
110		envConfig,
111	}: {
112		envConfig: Record<string, unknown>;
113	}): EnvironmentVariables {
114		const validatedConfig = plainToInstance(EnvironmentVariables, envConfig, {
115			enableImplicitConversion: true,
116		});
117	
118		const errors = validateSync(validatedConfig, {
119			skipMissingProperties: false,
120			forbidUnknownValues: true,
121			stopAtFirstError: true,
122			forbidNonWhitelisted: true,
123		});
124	
125		if (errors.length > 0) {
126			Logger.error('Config validation error', errors);
127			throw new Error(errors.toString());
128		}
129	
130		return validatedConfig;
131	}
